function f(t){return(typeof t=="string"?new Date(t):t).toLocaleString("es-CO",{timeZone:"America/Bogota",hour:"2-digit",minute:"2-digit",hour12:!0})}function c(t){let o=new Date,r=new Date(t),n=o.getTime()-r.getTime(),i=Math.floor(n/6e4),a=Math.floor(n/36e5),e=Math.floor(n/864e5);return i<1?"Ahora":i<60?`Hace ${i} min`:a<24?`Hace ${a}h`:e===1?"Ayer":e<7?["Domingo","Lunes","Martes","Miercoles","Jueves","Viernes","Sabado"][r.getDay()]:e<30?`Hace ${e} dias`:r.toLocaleDateString("es-CO")}export{f as a,c as b};
